                        new_kvpr = new_pressure / new_avail
                        old_kvpr = pressure_sum[gpu_id] / max(GPU_MEM - used_mem[gpu_id], 1)
                        increase = new_kvpr - old_kvpr
                    else:
                        increase = float('inf')

