def compute_model_placement(gpu_num, models):
    GPU_MEM = 80

    def kvpr_for_gpu(model_list):
        if not model_list:
            return 0.0
        total_pressure = sum(m.req_rate / m.slo for m in model_list)
        total_size = sum(m.model_size for m in model_list)
        remaining = GPU_MEM - total_size
        if remaining <= 0:
            return float('inf')
        return total_pressure / remaining

    # Sort models by pressure density (pressure/size) in descending order
    sorted_models = sorted(models, key=lambda m: (m.req_rate / m.slo) / m.model_size if m.model_size > 0 else float('inf'), reverse=True)

    # Initialize placement
    placement = {i: [] for i in range(gpu_num)}
    used_mem = [0] * gpu_num
    total_pressure = [0.0] * gpu_num

    # Greedy initial assignment
    for model in sorted_models:
        best_gpu = -1
        best_kvpr = float('inf')

        for gpu_id in range(gpu_num):
            if used_mem[gpu_id] + model.model_size <= GPU_MEM:
                new_mem = used_mem[gpu_id] + model.model_size
                new_press = total_pressure[gpu_id] + (model.req_rate / model.slo)
                remaining = GPU_MEM - new_mem
                if remaining > 0:
                    new_kvpr = new_press / remaining
                    if new_kvpr < best_kvpr:
                        best_kvpr = new_kvpr
                        best_gpu = gpu_id

        if best_gpu == -1:
            # Fallback to GPU with most free memory
            best_gpu = max(range(gpu_num), key=lambda i: GPU_MEM - used_mem[i])

        placement[best_gpu].append(model)
        used_mem[best_gpu] += model.model_size
        total_pressure[best_gpu] += model.req_rate / model.slo

    # Local search with swaps
    def get_max_kvpr():
        return max(kvpr_for_gpu(placement[i]) for i in range(gpu_num))

    current_max_kvpr = get_max_kvpr()

    improved = True
    while improved:
        improved = False
        for g1 in range(gpu_num):
            for g2 in range(g1 + 1, gpu_num):
                if not placement[g1] or not placement[g2]:
                    continue

                for m1 in placement[g1]:
                    for m2 in placement[g2]:
                        # Check memory constraints
                        new_mem1 = used_mem[g1] - m1.model_size + m2.model_size
                        new_mem2 = used_mem[g2] - m2.model_size + m1.model_size

                        if new_mem1 > GPU_MEM or new_mem2 > GPU_MEM:
                            continue

